function SqlBuild-RestoreDatabase {
    param ( [string]$ConnectionString, [string]$Database, [string]$BackupPath, [bool]$Compressed = $false)
    $backupBytes = [System.IO.File]::ReadAllBytes($BackupPath)
    $conn = New-Object System.Data.SQLClient.SQLConnection
    $handler = [System.Data.SqlClient.SqlInfoMessageEventHandler] {param($sender, $event) Write-Host $event.Message };
    $conn.add_InfoMessage($handler); 
    $conn.FireInfoMessageEventOnUserErrors = $true;
    $conn.ConnectionString = $ConnectionString
    $conn.Open()
    $command = $conn.CreateCommand()
    $command.CommandText = "if ((select value_in_use from sys.configurations where name = 'clr enabled') = 0)
begin
    Exec sp_configure 'show advanced options', 1; RECONFIGURE; exec sp_configure 'clr enabled', 1; RECONFIGURE; EXEC sp_configure 'show advanced options', 0; RECONFIGURE;
end

declare @hash varbinary(64) = CONVERT(varbinary(64), '74A7148D9DCDC162B82E6CA35736FE706A75B2C9001BF844DBAE705BDD2E08B44061EB8C297FB0FC98709972318B50C4611E43B559317BCB16EC2B11A23232E8', 2);
BEGIN TRY
    exec sp_add_trusted_assembly @hash, N'sqlbuildrestore, version=0.0.0.0, culture=neutral, publickeytoken=null, processorarchitecture=msil';
    create assembly [sqlbuild.restore] authorization [dbo] from 
    with permission_set = unsafe;
    execute sp_executesql N'create procedure RestoreBackup(@name nvarchar(max), @backup varbinary(max), @compressed bit = 0) as external name [sqlbuild.restore].[SQLBuild.Functions].RestoreBackup'
    exec RestoreBackup @name, @backup, @compressed
END TRY
BEGIN CATCH print ERROR_MESSAGE() END CATCH

BEGIN TRY exec sp_drop_trusted_assembly @hash END TRY BEGIN CATCH END CATCH
BEGIN TRY drop procedure RestoreBackup END TRY BEGIN CATCH END CATCH
BEGIN TRY drop assembly [sqlbuild.restore] END TRY BEGIN CATCH END CATCH"
    $command.Parameters.Add($(New-Object System.Data.SQLClient.SqlParameter "@backup", $backupBytes)) > $null    
    $command.Parameters.Add($(New-Object System.Data.SQLClient.SqlParameter "@name", $Database)) > $null
    $command.Parameters.Add($(New-Object System.Data.SQLClient.SqlParameter "@compressed", $Compressed)) > $null
    $command.ExecuteNonQuery() > $null
    $conn.Close()
}
